public class Main {
  public static void main(String[] args) {
    int number = 10;
    int divisor = 0;
    try {
      int result = number / divisor;
      System.out.println("Nəticə: " + result);
    } catch (ArithmeticException e) {
      System.out.println("Səhv: Sıfıra bölünmə! Mesaj: " + e.getMessage());
    }
  }
}
// Çıxış: Səhv: Sıfıra bölünmə! Mesaj: / by zero

public class Main {
  public static void checkAge(int age) throws IllegalArgumentException {
    if (age < 18) {
      throw new IllegalArgumentException("Yaş 18-dən kiçikdir!");
    }
    System.out.println("Yaş uyğundur: " + age);
  }

  public static void main(String[] args) {
    try {
      checkAge(16);
    } catch (IllegalArgumentException e) {
      System.out.println("Səhv: " + e.getMessage());
    }
  }
}
// Çıxış: Səhv: Yaş 18-dən kiçikdir!

